#[scope = "dialog"]
pub enum Part {
    /// The root container element.
    Root,

    /// The trigger button that opens the dialog.
    Trigger,

    /// The semi-transparent backdrop behind the content.
    Backdrop,

    /// The wrapper element that positions the content.
    Positioner,

