    /// backdrop. Adapters MUST consult [`Props::on_interact_outside`] (with
    /// a [`DismissAttempt`]) before calling this method.
    pub fn on_backdrop_click(&self) {
        (self.send)(Event::CloseOnBackdropClick);
    }

